409	    fn handle_key_inner(&mut self, key: UiKey) -> Vec<UiAction> {
410	        match key {
411	            UiKey::MouseClick { column, row } => {
412	                self.pending = None;
413	                self.clear_visual_selection();
414	                return self.handle_mouse_click(column, row);
415	            }
416	            UiKey::MouseScrollUp { column, row } => {
417	                self.pending = None;
418	                self.handle_mouse_scroll(column, row, true);
419	                return Vec::new();
420	            }
421	            UiKey::MouseScrollDown { column, row } => {
422	                self.pending = None;
423	                self.handle_mouse_scroll(column, row, false);
424	                return Vec::new();
425	            }
426	            _ => {}
427	        }
428	
429	        if self.visual_selection.is_some() {
430	            if let Some(pending) = self.pending.take() {
431	                return self.handle_pending_key(pending, key);
432	            }
433	            return self.handle_visual_key(key);
434	        }
435	
436	        if let Some(pending) = self.pending.take() {
437	            return self.handle_pending_key(pending, key);
438	        }
439	
440	        match key {
441	            UiKey::Esc => {
442	                self.mode = UiMode::Command;
443	                self.clear_visual_selection();
444	                Vec::new()
445	            }
446	            UiKey::CtrlW if self.mode == UiMode::Command => {
447	                self.pending = Some(PendingKey::CtrlW);
448	                Vec::new()
449	            }
450	            UiKey::Char('g') if self.mode == UiMode::Command => {
451	                self.pending = Some(PendingKey::G);
452	                Vec::new()
453	            }
454	            UiKey::Char('i') if self.mode == UiMode::Command => {
455	                self.mode = UiMode::Insert;
456	                Vec::new()
457	            }
458	            UiKey::Char(':') if self.mode == UiMode::Command => {
459	                self.mode = UiMode::Prompt;
460	                Vec::new()
461	            }
462	            UiKey::Char(',') if self.mode == UiMode::Command => {
463	                self.clear_visual_selection();
464	                self.left_visible = !self.left_visible;
465	                self.focus = if self.left_visible {
466	                    PaneFocus::Left
467	                } else {
468	                    PaneFocus::Right
469	                };
470	                Vec::new()
471	            }
472	            UiKey::Char('v') if self.mode == UiMode::Command => {
473	                self.start_visual_selection(VisualSelectionKind::Character);
474	                Vec::new()
475	            }
476	            UiKey::Char('V') if self.mode == UiMode::Command => {
477	                self.start_visual_selection(VisualSelectionKind::Line);
478	                Vec::new()
479	            }
480	            UiKey::Char('\u{16}') if self.mode == UiMode::Command => {
481	                self.start_visual_selection(VisualSelectionKind::Block);
482	                Vec::new()
483	            }
484	            UiKey::Char('y') if self.mode == UiMode::Command => {
485	                self.pending = Some(PendingKey::Yank);
486	                Vec::new()
487	            }
488	            UiKey::Char('Y') if self.mode == UiMode::Command => {
489	                self.yank_current_line();
490	                Vec::new()
491	            }
492	            UiKey::Char('j') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
493	                self.move_control_selection(1);
494	                self.select_control_row_surface();
495	                Vec::new()
496	            }
497	            UiKey::Down if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
498	                self.move_control_selection(1);
499	                self.select_control_row_surface();
500	                Vec::new()
501	            }
502	            UiKey::Right if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
503	                self.move_control_selection(1);
504	                self.select_control_row_surface();
505	                Vec::new()
506	            }
507	            UiKey::Char('k') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
508	                self.move_control_selection(-1);
509	                self.select_control_row_surface();
510	                Vec::new()
511	            }
512	            UiKey::Up if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
513	                self.move_control_selection(-1);
514	                self.select_control_row_surface();
515	                Vec::new()
516	            }
517	            UiKey::Left if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
518	                self.move_control_selection(-1);
519	                self.select_control_row_surface();
520	                Vec::new()
521	            }
522	            UiKey::Char('l') if self.mode == UiMode::Command && self.focus == PaneFocus::Left => {
523	                self.open_control_selection();
