1065	    fn start_visual_selection(&mut self, kind: VisualSelectionKind) {
1066	        let Some(position) = self.focus_cursor_text_position(self.focus) else {
1067	            return;
1068	        };
1069	        self.visual_selection = Some(VisualSelection {
1070	            focus: self.focus,
1071	            kind,
1072	            anchor: position,
1073	            cursor: position,
1074	        });
