1088	    fn move_visual_row(&mut self, delta: isize) {
1089	        let Some(mut selection) = self.visual_selection else {
1090	            return;
1091	        };
1092	        let lines = self.pane_line_texts(selection.focus);
1093	        if lines.is_empty() {
1094	            return;
1095	        }
1096	        let max_row = lines.len().saturating_sub(1) as isize;
1097	        let row = (selection.cursor.row as isize + delta).clamp(0, max_row) as usize;
1098	        selection.cursor.row = row;
1099	        selection.cursor.column = clamp_column_for_line(&lines[row], selection.cursor.column);
1100	        self.visual_selection = Some(selection);
1101	    }
1102	
1103	    fn move_visual_to_row(&mut self, row: usize) {
1104	        let Some(mut selection) = self.visual_selection else {
1105	            return;
1106	        };
1107	        let lines = self.pane_line_texts(selection.focus);
1108	        if lines.is_empty() {
1109	            return;
