1192	        }
1193	
1194	        let (start_row, end_row) = ordered_rows(selection);
1195	        let start_row = start_row.min(lines.len().saturating_sub(1));
1196	        let end_row = end_row.min(lines.len().saturating_sub(1));
1197	
1198	        if linewise || selection.kind == VisualSelectionKind::Line {
1199	            let mut text = lines[start_row..=end_row].join("\n");
1200	            text.push('\n');
1201	            return Some(text);
1202	        }
1203	
1204	        let selected = (start_row..=end_row)
1205	            .map(|row| {
1206	                let line = &lines[row];
1207	                let (start, end) = selection_columns_for_line(selection, row, line);
