 756	    fn prompt_view(&self, prompt: &str, prompt_cursor: usize) -> PromptView {
 757	        let width = usize::from(self.width.max(1));
 758	        let input_width = width.saturating_sub(1);
 759	        let max_cursor_offset = width.saturating_sub(2);
 760	        let cursor_chars = cursor_char_count(prompt, prompt_cursor);
 761	        let start = cursor_chars.saturating_sub(max_cursor_offset);
 762	        let visible_prompt = prompt
 763	            .chars()
 764	            .skip(start)
 765	            .take(input_width)
 766	            .collect::<String>();
 767	        let cursor_offset = cursor_chars.saturating_sub(start).min(max_cursor_offset);
 768	        let cursor_column = if self.width <= 1 {
 769	            1
 770	        } else {
 771	            cursor_offset.saturating_add(2).min(width) as u16
 772	        };
 773	        PromptView {
 774	            line: format!(":{visible_prompt}"),
 775	            cursor_column,
 776	        }
 777	    }
