1465	    fn right_cursor_position_with_cursor(
1466	        &self,
1467	        right_content: &str,
1468	        cursor_column: Option<usize>,
1469	    ) -> (u16, u16) {
1470	        let layout = self.layout();
1471	        let inner_width = layout.right_width.saturating_sub(2).max(1);
1472	        let lines = right_content.lines().collect::<Vec<_>>();
1473	        let Some(line) = lines.last().copied() else {
1474	            return (2, layout.left_width.saturating_add(2));
1475	        };
1476	        if !line.starts_with("chat> ") {
1477	            return (2, layout.left_width.saturating_add(2));
1478	        }
1479	        let previous_rows = lines[..lines.len() - 1]
1480	            .iter()
1481	            .map(|line| visual_rows(line, inner_width))
1482	            .sum::<u16>();
1483	        let line_chars = line.chars().count();
1484	        let line_len = cursor_column
1485	            .unwrap_or(line_chars)
1486	            .min(line_chars)
1487	            .min(usize::from(u16::MAX)) as u16;
1488	        let row = 2_u16
1489	            .saturating_add(previous_rows)
1490	            .saturating_add(line_len / inner_width);
1491	        let column = layout
1492	            .left_width
1493	            .saturating_add(2)
1494	            .saturating_add(line_len % inner_width);
1495	        (row, column)
1496	    }
