1664	fn base64_encode(bytes: &[u8]) -> String {
1665	    const TABLE: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
1666	    let mut encoded = String::with_capacity(bytes.len().div_ceil(3) * 4);
1667	    for chunk in bytes.chunks(3) {
1668	        let b0 = chunk[0];
1669	        let b1 = *chunk.get(1).unwrap_or(&0);
1670	        let b2 = *chunk.get(2).unwrap_or(&0);
1671	
1672	        encoded.push(TABLE[(b0 >> 2) as usize] as char);
1673	        encoded.push(TABLE[(((b0 & 0b0000_0011) << 4) | (b1 >> 4)) as usize] as char);
1674	        if chunk.len() > 1 {
1675	            encoded.push(TABLE[(((b1 & 0b0000_1111) << 2) | (b2 >> 6)) as usize] as char);
1676	        } else {
1677	            encoded.push('=');
1678	        }
1679	        if chunk.len() > 2 {
1680	            encoded.push(TABLE[(b2 & 0b0011_1111) as usize] as char);
1681	        } else {
1682	            encoded.push('=');
1683	        }
1684	    }
1685	    encoded
1686	}
