1752	fn buffer_to_string(buffer: &Buffer) -> String {
1753	    const ANSI_REVERSE_VIDEO: &str = "\u{1b}[7m";
1754	    const ANSI_RESET: &str = "\u{1b}[0m";
1755	    let mut output = String::new();
1756	    for y in 0..buffer.area.height {
1757	        let mut reversed = false;
1758	        for x in 0..buffer.area.width {
1759	            let cell = buffer.get(x, y);
1760	            let cell_reversed = cell.modifier.contains(Modifier::REVERSED);
1761	            if cell_reversed != reversed {
1762	                output.push_str(if cell_reversed {
1763	                    ANSI_REVERSE_VIDEO
1764	                } else {
1765	                    ANSI_RESET
1766	                });
1767	                reversed = cell_reversed;
1768	            }
1769	            output.push_str(&cell.symbol);
1770	        }
1771	        if reversed {
1772	            output.push_str(ANSI_RESET);
1773	        }
1774	        if y + 1 < buffer.area.height {
1775	            output.push_str("\r\n");
1776	        }
1777	    }
1778	    output
1779	}
