 75	    pub fn handle_bytes(&mut self, bytes: &[u8]) -> bool {
 76	        let mut index = 0;
 77	        while index < bytes.len() {
 78	            if let Some((key, len)) = parse_key_sequence(&bytes[index..]) {
 79	                self.handle_input(HarnessInput::Key(key));
 80	                index += len;
 81	            } else if !self.handle_byte(bytes[index]) {
 82	                return false;
 83	            } else {
 84	                index += 1;
 85	            }
 86	        }
 87	        self.finish_pending_escape_sequence();
 88	        !self.quit
 89	    }
