 91	    pub fn handle_byte(&mut self, byte: u8) -> bool {
 92	        if self.quit {
 93	            return false;
 94	        }
 95	
 96	        if self.continue_escape_sequence(byte) {
 97	            return !self.quit;
 98	        }
 99	
100	        if byte == 27 {
101	            let defer_escape = self.defer_escape_key();
102	            self.escape_sequence = Some(PendingEscapeSequence {
103	                bytes: vec![27],
104	                mode_before: self.ui.mode(),
105	                escape_dispatched: !defer_escape,
106	            });
107	            if !defer_escape {
108	                self.handle_input(HarnessInput::Key(UiKey::Esc));
109	            }
110	            return !self.quit;
111	        }
112	
113	        let Some(input) = HarnessInput::from_byte(byte) else {
114	            return true;
115	        };
116	        self.handle_input(input);
117	        !self.quit
118	    }
