 454	    fn handle_byte_without_poll(&mut self, byte: u8) -> bool {
 455	        if self.quit {
 456	            return false;
 457	        }
 458	
 459	        if self.continue_escape_sequence(byte) {
 460	            return !self.quit;
 461	        }
 462	
 463	        if byte == 27 {
 464	            let defer_escape = self.defer_escape_key();
 465	            self.escape_sequence = Some(PendingEscapeSequence {
 466	                bytes: Vec::new(),
 467	                mode_before: self.ui.mode(),
 468	                escape_dispatched: !defer_escape,
 469	            });
 470	            if !defer_escape {
 471	                self.handle_input(TerminalAppInput::Key(UiKey::Esc));
 472	            }
 473	            return !self.quit;
 474	        }
 475	
 476	        let Some(input) = self.input_from_byte(byte) else {
 477	            return true;
 478	        };
 479	        self.handle_input(input);
 480	        !self.quit
 481	    }
