 500	    fn handle_input(&mut self, input: TerminalAppInput) {
 501	        match input {
 502	            TerminalAppInput::Quit => {
 503	                self.request_quit();
 504	            }
 505	            TerminalAppInput::Interrupt => {
 506	                self.ui.show_ctrl_c_exit_notice();
 507	                if self.ui.focus() == PaneFocus::Right
 508	                    && let Some(agent_id) = self.ui.selected_agent().cloned()
 509	                {
 510	                    self.controller.interrupt_agent(&agent_id);
 511	                    self.apply_controller_events();
 512	                }
 513	                self.dirty = true;
 514	            }
 515	            TerminalAppInput::Backspace if self.ui.mode() == UiMode::Prompt => {
 516	                self.prompt_buffer.backspace();
 517	                self.prompt_history_index = None;
 518	                self.prompt_history_draft = None;
 519	                self.dirty = true;
 520	            }
 521	            TerminalAppInput::Backspace if self.ui.mode() == UiMode::Insert => {
 522	                self.chat_buffer.backspace();
 523	                self.chat_history_index = None;
 524	                self.chat_history_draft = None;
 525	                self.dirty = true;
 526	            }
 527	            TerminalAppInput::Enter if self.ui.mode() == UiMode::Prompt => {
 528	                let line = self.prompt_buffer.trimmed_string();
 529	                self.prompt_buffer.clear();
 530	                self.ui.handle_key(UiKey::Esc);
 531	                if !line.is_empty() {
 532	                    self.prompt_history.push(line.clone());
 533	                    self.prompt_history_index = None;
 534	                    self.prompt_history_draft = None;
 535	                    self.handle_command_line(&line);
 536	                } else {
 537	                    self.prompt_history_index = None;
 538	                    self.prompt_history_draft = None;
 539	                }
 540	                self.dirty = true;
 541	            }
 542	            TerminalAppInput::Enter if self.ui.mode() == UiMode::Insert => {
 543	                self.send_chat_buffer();
 544	            }
 545	            TerminalAppInput::Char('/') if self.should_start_agent_slash_command() => {
 546	                self.start_agent_slash_command();
 547	                self.dirty = true;
 548	            }
 549	            TerminalAppInput::LineBreak if self.ui.mode() == UiMode::Insert => {
 550	                self.chat_buffer.push('\n');
 551	                self.chat_history_index = None;
 552	                self.chat_history_draft = None;
 553	                self.dirty = true;
 554	            }
 555	            TerminalAppInput::PasteStart => {
 556	                self.paste_mode = true;
 557	                self.skip_next_paste_lf = false;
 558	            }
 559	            TerminalAppInput::PasteEnd => {
 560	                self.paste_mode = false;
 561	                self.skip_next_paste_lf = false;
 562	            }
 563	            TerminalAppInput::Char(ch) if self.ui.mode() == UiMode::Prompt => {
 564	                self.prompt_buffer.push(ch);
 565	                self.prompt_history_index = None;
 566	                self.prompt_history_draft = None;
 567	                self.dirty = true;
 568	            }
 569	            TerminalAppInput::Char(ch) if self.ui.mode() == UiMode::Insert => {
 570	                self.chat_buffer.push(ch);
 571	                self.chat_history_index = None;
 572	                self.chat_history_draft = None;
 573	                self.dirty = true;
 574	            }
 575	            TerminalAppInput::Key(UiKey::Left) if self.ui.mode() == UiMode::Prompt => {
 576	                self.prompt_buffer.move_left();
 577	                self.dirty = true;
 578	            }
 579	            TerminalAppInput::Key(UiKey::Right) if self.ui.mode() == UiMode::Prompt => {
 580	                self.prompt_buffer.move_right();
 581	                self.dirty = true;
 582	            }
 583	            TerminalAppInput::Key(UiKey::Up) if self.ui.mode() == UiMode::Prompt => {
 584	                self.recall_prompt_history(-1);
 585	                self.dirty = true;
 586	            }
 587	            TerminalAppInput::Key(UiKey::Down) if self.ui.mode() == UiMode::Prompt => {
 588	                self.recall_prompt_history(1);
 589	                self.dirty = true;
 590	            }
 591	            TerminalAppInput::Key(UiKey::Left) if self.should_route_chat_arrow() => {
 592	                self.chat_buffer.move_left();
 593	                self.dirty = true;
 594	            }
 595	            TerminalAppInput::Key(UiKey::Right) if self.should_route_chat_arrow() => {
 596	                self.chat_buffer.move_right();
 597	                self.dirty = true;
 598	            }
 599	            TerminalAppInput::Key(UiKey::Up) if self.should_route_chat_arrow() => {
 600	                self.recall_chat_history(-1);
 601	                self.dirty = true;
 602	            }
 603	            TerminalAppInput::Key(UiKey::Down) if self.should_route_chat_arrow() => {
 604	                self.recall_chat_history(1);
 605	                self.dirty = true;
 606	            }
 607	            TerminalAppInput::Key(UiKey::Esc) => {
 608	                self.prompt_buffer.clear();
 609	                let actions = self.ui.handle_key(UiKey::Esc);
 610	                self.record_actions(actions);
 611	                self.dirty = true;
 612	            }
 613	            TerminalAppInput::Key(key) => {
 614	                let actions = self.ui.handle_key(key);
 615	                self.record_actions(actions);
 616	                self.dirty = true;
 617	            }
 618	            TerminalAppInput::Char(ch) => {
 619	                let actions = self.ui.handle_key(UiKey::Char(ch));
 620	                self.record_actions(actions);
 621	                self.dirty = true;
 622	            }
 623	            TerminalAppInput::Backspace | TerminalAppInput::Enter | TerminalAppInput::LineBreak => {
 624	            }
 625	        }
 626	    }
