 670	    fn apply_controller_events(&mut self) {
 671	        let events = self.controller.drain_events();
 672	        if events.is_empty() {
 673	            return;
 674	        }
 675	        for event in events {
 676	            match event {
 677	                WorkLeafEvent::AgentAdded { session } | WorkLeafEvent::AgentUpdated { session } => {
 678	                    self.upsert_cached_session(session.clone());
 679	                    self.apply_session_to_ui(&session);
 680	                }
 681	                WorkLeafEvent::AgentStatusUpdated {
 682	                    agent_id,
 683	                    kind,
 684	                    title,
 685	                    feature,
 686	                    loading,
 687	                } => {
 688	                    let session =
 689	                        self.upsert_cached_session_status(agent_id, kind, title, feature, loading);
 690	                    self.apply_session_to_ui(&session);
 691	                }
 692	                WorkLeafEvent::AgentLineAppended { agent_id, line } => {
 693	                    self.append_cached_agent_line(&agent_id, line);
 694	                }
 695	                WorkLeafEvent::AgentSelected { agent_id } => {
 696	                    let _ = self.ui.activate_agent_chat(&agent_id);
 697	                }
 698	                WorkLeafEvent::CommandTranscriptLine { line } => {
 699	                    self.snapshot.command_transcript.push(line);
 700	                }
 701	                WorkLeafEvent::QuitRequested => {
 702	                    self.quit = true;
 703	                }
 704	            }
 705	        }
 706	        self.dirty = true;
 707	    }
