 711	            .snapshot
 712	            .sessions
 713	            .iter_mut()
 714	            .find(|existing| existing.id == session.id)
 715	        {
 716	            *existing = session;
 717	        } else {
 718	            self.snapshot.sessions.push(session);
 719	            self.snapshot
 720	                .sessions
 721	                .sort_by(|left, right| left.id.as_str().cmp(right.id.as_str()));
 722	        }
 723	    }
