 839	    fn input_from_byte(&mut self, byte: u8) -> Option<TerminalAppInput> {
 840	        if self.paste_mode {
 841	            match byte {
 842	                13 => {
 843	                    self.skip_next_paste_lf = true;
 844	                    return Some(TerminalAppInput::LineBreak);
 845	                }
 846	                10 if self.skip_next_paste_lf => {
 847	                    self.skip_next_paste_lf = false;
 848	                    return None;
 849	                }
 850	                10 => return Some(TerminalAppInput::LineBreak),
 851	                _ => {
 852	                    self.skip_next_paste_lf = false;
 853	                }
 854	            }
 855	        }
 856	        TerminalAppInput::from_byte(byte)
 857	    }
