 859	    fn recall_prompt_history(&mut self, delta: isize) {
 860	        if self.prompt_history.is_empty() {
 861	            return;
 862	        }
 863	
 864	        if self.prompt_history_index.is_none() {
 865	            self.prompt_history_draft = Some(self.prompt_buffer.as_str().to_string());
 866	        }
 867	
 868	        let current = self
 869	            .prompt_history_index
 870	            .unwrap_or(self.prompt_history.len()) as isize;
 871	        let next = current + delta;
 872	        if next < 0 {
 873	            self.prompt_history_index = Some(0);
 874	            self.prompt_buffer.replace(&self.prompt_history[0]);
 875	        } else if next >= self.prompt_history.len() as isize {
 876	            self.prompt_history_index = None;
 877	            let draft = self.prompt_history_draft.take().unwrap_or_default();
 878	            self.prompt_buffer.replace(&draft);
 879	        } else {
 880	            let next = next as usize;
 881	            self.prompt_history_index = Some(next);
 882	            self.prompt_buffer.replace(&self.prompt_history[next]);
 883	        }
 884	    }
