 887	        if self.chat_history.is_empty() {
 888	            return;
 889	        }
 890	
 891	        if self.chat_history_index.is_none() {
 892	            self.chat_history_draft = Some(self.chat_buffer.as_str().to_string());
 893	        }
 894	
 895	        let current = self.chat_history_index.unwrap_or(self.chat_history.len()) as isize;
 896	        let next = current + delta;
 897	        if next < 0 {
 898	            self.chat_history_index = Some(0);
 899	            self.chat_buffer.replace(&self.chat_history[0]);
 900	        } else if next >= self.chat_history.len() as isize {
 901	            self.chat_history_index = None;
 902	            let draft = self.chat_history_draft.take().unwrap_or_default();
 903	            self.chat_buffer.replace(&draft);
 904	        } else {
 905	            let next = next as usize;
 906	            self.chat_history_index = Some(next);
 907	            self.chat_buffer.replace(&self.chat_history[next]);
