 943	    fn continue_escape_sequence(&mut self, byte: u8) -> bool {
 944	        let Some(sequence) = self.escape_sequence.as_mut() else {
 945	            return false;
 946	        };
 947	
 948	        if sequence.bytes.is_empty() && byte != b'[' {
 949	            let sequence = self
 950	                .escape_sequence
 951	                .take()
 952	                .expect("escape sequence is present");
 953	            self.dispatch_pending_escape_if_needed(&sequence);
 954	            return false;
 955	        }
 956	
 957	        sequence.bytes.push(byte);
 958	        if is_complete_control_sequence(&sequence.bytes) {
 959	            let sequence = self
 960	                .escape_sequence
 961	                .take()
 962	                .expect("escape sequence is present");
 963	            if sequence.escape_dispatched
 964	                && sequence.mode_before == UiMode::Insert
 965	                && self.ui.mode() != UiMode::Insert
 966	            {
 967	                let actions = self.ui.handle_key(UiKey::Char('i'));
 968	                self.record_actions(actions);
 969	            }
 970	            if let Some(input) = parse_control_sequence(&sequence.bytes) {
 971	                self.handle_input(input);
 972	            }
 973	        } else if sequence.bytes.len() > MAX_ESCAPE_SEQUENCE {
 974	            let sequence = self
 975	                .escape_sequence
 976	                .take()
 977	                .expect("escape sequence is present");
 978	            self.dispatch_pending_escape_if_needed(&sequence);
 979	        }
 980	
 981	        true
 982	    }
 983	}
