1006	fn parse_control_sequence(sequence: &[u8]) -> Option<TerminalAppInput> {
1007	    match sequence {
1008	        [b'[', b'A'] => Some(TerminalAppInput::Key(UiKey::Up)),
1009	        [b'[', b'B'] => Some(TerminalAppInput::Key(UiKey::Down)),
1010	        [b'[', b'C'] => Some(TerminalAppInput::Key(UiKey::Right)),
1011	        [b'[', b'D'] => Some(TerminalAppInput::Key(UiKey::Left)),
1012	        [b'[', b'2', b'0', b'0', b'~'] => Some(TerminalAppInput::PasteStart),
1013	        [b'[', b'2', b'0', b'1', b'~'] => Some(TerminalAppInput::PasteEnd),
1014	        [b'[', b'1', b'3', b';', b'2', b'u']
1015	        | [b'[', b'1', b'3', b';', b'2', b'~']
1016	        | [b'[', b'2', b'7', b';', b'2', b';', b'1', b'3', b'~'] => {
1017	            Some(TerminalAppInput::LineBreak)
1018	        }
1019	        _ => parse_sgr_mouse_event(sequence).map(TerminalAppInput::Key),
1020	    }
1021	}
