1023	fn parse_sgr_mouse_event(sequence: &[u8]) -> Option<UiKey> {
1024	    let final_byte = *sequence.last()?;
1025	    if !sequence.starts_with(b"[<") || !matches!(final_byte, b'M' | b'm') {
1026	        return None;
1027	    }
1028	
1029	    let body = std::str::from_utf8(&sequence[2..sequence.len() - 1]).ok()?;
1030	    let mut parts = body.split(';');
1031	    let button = parts.next()?.parse::<u16>().ok()?;
1032	    let column = parts.next()?.parse::<u16>().ok()?;
1033	    let row = parts.next()?.parse::<u16>().ok()?;
1034	    if parts.next().is_some() {
1035	        return None;
1036	    }
1037	
1038	    let button_kind = button & !0b0001_1100_u16;
1039	    match (button_kind, final_byte) {
1040	        (64, b'M') => Some(UiKey::MouseScrollUp { column, row }),
1041	        (65, b'M') => Some(UiKey::MouseScrollDown { column, row }),
1042	        (_, b'M' | b'm') if button_kind < 64 && button & 0b11 == 0 => {
1043	            Some(UiKey::MouseClick { column, row })
1044	        }
1045	        _ => None,
1046	    }
1047	}
