234	    fn execute_prompt(&mut self, line: &str) {
235	        if matches!(line, "quit" | "exit" | "q") {
236	            self.quit = true;
237	            return;
238	        }
239	
240	        let new_prompt = if line == "new" {
241	            Some("interactive task discovery")
