254	                .expect("generated fixture agent is registered");
255	            self.transcript
256	                .push(format!("agent {agent_id} launched for: {prompt}"));
257	            return;
258	        }
259	
260	        match line {
261	            "help" | "?" => {
262	                self.transcript
263	                    .push("commands: new [prompt...], review, linearize, quit".into());
264	            }
265	            "review" => self.transcript.push("fixture review: no findings".into()),
266	            "linearize" => self
267	                .transcript
